/* === assets/js/modules/db_source_selector.js === */
/**
 * VYRA — DB Source Selector (v3.20.0 / Faz 1f)
 * =============================================
 * "Veritabanında Ara" modunda kullanıcının yetkili olduğu veri kaynaklarını
 * chip-tabanlı tek-seçimli (radio group) UI'da gösterir. Seçim aktif olduğunda
 * dialog gönderiminde `source_id` payload'a eklenir.
 *
 * Exposed API: window.DbSourceSelector
 *   load(force?)             → /api/data-sources/ çağırır, chip'leri render eder
 *   show() / hide()          → DB modu/diğer modlar arası geçişlerde
 *   getSelectedSourceId()    → seçili kaynak ID (null olabilir)
 *   getSelectedSourceName()  → seçili kaynak adı (label için)
 *   setSelectedSourceId(id)  → programatik seçim (örn. localStorage restore)
 *   isReady()                → en az bir kaynak yüklendi mi
 *   onChange(cb)             → seçim değişikliğinde dispatch
 *
 * HEBE:
 *   - role="radiogroup", her chip role="radio" + aria-checked
 *   - Klavye: Arrow / Home / End / Enter|Space
 *   - Empty state ve loading state ayrı görsel
 *   - Tüm renkler CSS variable (no hard-coded hex)
 */
(function () {
    'use strict';

    const STORAGE_KEY = 'vyra_selected_source_id';
    const API_BASE = (window.API_BASE_URL || 'http://localhost:8002') + '/api';

    // ---- State ----
    let sources = [];           // [{id, name, db_type, company_name, ...}]
    let selectedId = null;
    let loadPromise = null;     // in-flight load (dedup)
    let lastError = null;
    const changeListeners = new Set();

    // ---- Helpers ----
    function $bar() { return document.getElementById('dbSourceBar'); }
    function $chips() { return document.getElementById('dbSourceChips'); }
    function $status() { return document.getElementById('dbSourceStatus'); }

    function dispatch() {
        for (const cb of changeListeners) {
            try { cb(selectedId, getSelectedSourceName()); } catch (e) { console.error('[DbSourceSelector] listener error:', e); }
        }
    }

    function getSelectedSourceName() {
        const s = sources.find(x => x.id === selectedId);
        return s ? (s.name || `#${s.id}`) : null;
    }

    function persist() {
        try {
            if (selectedId != null) localStorage.setItem(STORAGE_KEY, String(selectedId));
            else localStorage.removeItem(STORAGE_KEY);
        } catch (_) { /* private mode vb. — yok say */ }
    }

    function restorePersisted() {
        try {
            const raw = localStorage.getItem(STORAGE_KEY);
            if (raw) {
                const n = parseInt(raw, 10);
                if (!Number.isNaN(n)) return n;
            }
        } catch (_) {}
        return null;
    }

    // ---- Render ----
    function renderLoading() {
        const chips = $chips(); if (!chips) return;
        chips.innerHTML = '<span class="dsb-skeleton" aria-hidden="true"></span><span class="dsb-skeleton" aria-hidden="true"></span>';
        const st = $status(); if (st) { st.textContent = 'Yükleniyor…'; st.dataset.state = 'loading'; }
    }

    function renderError(msg) {
        const chips = $chips(); if (!chips) return;
        chips.innerHTML = '';
        const st = $status(); if (st) { st.textContent = msg; st.dataset.state = 'error'; }
    }

    function renderEmpty() {
        const chips = $chips(); if (!chips) return;
        chips.innerHTML = '';
        const st = $status();
        if (st) {
            st.textContent = 'Yetkili olduğunuz bir veri kaynağı yok. Yöneticinizden erişim talep edin.';
            st.dataset.state = 'empty';
        }
    }

    function renderChips() {
        const chips = $chips(); if (!chips) return;
        const st = $status(); if (st) { st.textContent = ''; st.dataset.state = 'ok'; }

        chips.innerHTML = '';
        for (const s of sources) {
            const isSel = (s.id === selectedId);
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'dsb-chip' + (isSel ? ' selected' : '');
            btn.dataset.sourceId = String(s.id);
            btn.setAttribute('role', 'radio');
            btn.setAttribute('aria-checked', isSel ? 'true' : 'false');
            btn.setAttribute('tabindex', isSel || (selectedId == null && s === sources[0]) ? '0' : '-1');
            btn.setAttribute('aria-label', `Veri kaynağı: ${s.name}${s.company_name ? ' / ' + s.company_name : ''}`);

            const dot = document.createElement('span');
            dot.className = 'dsb-chip-dot';
            dot.setAttribute('aria-hidden', 'true');

            const lbl = document.createElement('span');
            lbl.className = 'dsb-chip-label';
            lbl.textContent = s.name || `#${s.id}`;

            btn.appendChild(dot);
            btn.appendChild(lbl);
            btn.addEventListener('click', () => selectById(s.id));
            btn.addEventListener('keydown', onChipKeydown);
            chips.appendChild(btn);
        }
    }

    function onChipKeydown(ev) {
        const list = Array.from($chips()?.querySelectorAll('.dsb-chip') || []);
        if (list.length === 0) return;
        const i = list.indexOf(ev.currentTarget);
        if (i < 0) return;

        let nextIdx = -1;
        switch (ev.key) {
            case 'ArrowRight': case 'ArrowDown':
                nextIdx = (i + 1) % list.length; break;
            case 'ArrowLeft': case 'ArrowUp':
                nextIdx = (i - 1 + list.length) % list.length; break;
            case 'Home': nextIdx = 0; break;
            case 'End': nextIdx = list.length - 1; break;
            case 'Enter': case ' ':
                ev.preventDefault();
                const sid = parseInt(ev.currentTarget.dataset.sourceId, 10);
                if (!Number.isNaN(sid)) selectById(sid);
                return;
            default: return;
        }
        if (nextIdx >= 0) {
            ev.preventDefault();
            list[nextIdx].focus();
        }
    }

    function selectById(id) {
        if (id === selectedId) return;
        const exists = sources.some(s => s.id === id);
        if (!exists) return;
        selectedId = id;
        persist();
        renderChips();
        dispatch();
    }

    // ---- Load ----
    async function load(force) {
        if (loadPromise && !force) return loadPromise;
        const bar = $bar();
        if (bar) renderLoading();

        loadPromise = (async () => {
            try {
                // v3.34.0: vyraFetch — Auth + JSON + friendly error helper'da.
                const data = await window.vyraFetch('/data-sources/');
                sources = Array.isArray(data) ? data : [];
                lastError = null;

                // Persisted selection geçerli mi?
                const persisted = restorePersisted();
                if (persisted != null && sources.some(s => s.id === persisted)) {
                    selectedId = persisted;
                } else if (sources.length === 1) {
                    // Tek kaynak varsa otomatik seç (UX)
                    selectedId = sources[0].id;
                    persist();
                } else {
                    selectedId = null;
                    persist();
                }

                if (sources.length === 0) renderEmpty();
                else renderChips();
                dispatch();
            } catch (e) {
                lastError = String(e && e.message ? e.message : e);
                console.error('[DbSourceSelector] load hatası:', e);
                renderError('Veri kaynakları yüklenemedi. Tekrar deneyin.');
                dispatch();
            } finally {
                loadPromise = null;
            }
        })();
        return loadPromise;
    }

    // ---- Visibility ----
    function show() {
        const bar = $bar();
        if (bar) bar.removeAttribute('hidden');
        if (sources.length === 0 && !loadPromise) load();
    }

    function hide() {
        const bar = $bar();
        if (bar) bar.setAttribute('hidden', '');
    }

    function isReady() {
        return sources.length > 0;
    }

    function onChange(cb) {
        if (typeof cb === 'function') changeListeners.add(cb);
        return () => changeListeners.delete(cb);
    }

    // ---- Public API ----
    window.DbSourceSelector = {
        load,
        show,
        hide,
        isReady,
        onChange,
        getSelectedSourceId: () => selectedId,
        getSelectedSourceName,
        setSelectedSourceId: selectById,
        // Debug/test
        _state: () => ({ sources: sources.slice(), selectedId, lastError }),
    };
})();


/* === assets/js/modules/sample_data_preview.js === */
/**
 * sample_data_preview.js — v3.28.2 G3 (Frontend)
 * ------------------------------------------------
 * SSE event'i `selected_table_for_preview` geldiğinde aday tablonun cached
 * örnek satırlarını gösteren kart render eder.
 *
 * Backend akışı:
 *   1. deep_think_service.py SQL üretildikten sonra
 *      `selected_table_for_preview` event yayar (hint: {source_id, schema, table})
 *   2. dialog_chat.js bu case'de window.renderSampleDataPreview(parentEl, hint) çağırır
 *   3. Bu modül GET /api/data-sources/{id}/samples?schema&table'tan veri çeker
 *   4. Skeleton → kart (role=region) → execute event'i geldiğinde fade out
 *
 * SaaS / HEBE checklist:
 *   - role="region" + aria-labelledby
 *   - .skel-line placeholder (fetch sırasında)
 *   - Empty state CTA ("örnek veri toplama" yönlendirmesi)
 *   - data-tooltip "Aday tablo — sorgudan önce hızlı önizleme"
 *   - prefers-reduced-motion fallback CSS modülünde
 */
(function () {
    'use strict';

    const ENDPOINT_BASE = (window.API_BASE_URL || '') + '/api/data-sources';

    function _h(html) {
        const tpl = document.createElement('template');
        tpl.innerHTML = html.trim();
        return tpl.content.firstChild;
    }

    function _esc(s) {
        if (s == null) return '';
        return String(s)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;');
    }

    function _renderSkeleton(parentEl, hint) {
        const id = 'samplePreview_' + Date.now();
        const tableLabel = hint.schema ? `${hint.schema}.${hint.table}` : hint.table;
        const card = _h(`
            <section class="sample-preview-card sample-preview-loading"
                     role="region"
                     aria-labelledby="${id}_title"
                     aria-busy="true"
                     data-preview-id="${id}">
                <div class="sample-preview-header">
                    <h4 class="sample-preview-title" id="${id}_title">
                        <svg class="sample-preview-icon" viewBox="0 0 24 24" aria-hidden="true">
                            <path d="M3 5h18M3 12h18M3 19h18" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round"/>
                        </svg>
                        <span>Aday Tablo</span>
                        <code class="sample-preview-table-id">${_esc(tableLabel)}</code>
                    </h4>
                    <span class="sample-preview-badge" data-tooltip="Sorgudan önce hızlı önizleme">Önizleme</span>
                </div>
                <div class="sample-preview-body">
                    <div class="skel-line" style="width:96%"></div>
                    <div class="skel-line" style="width:82%"></div>
                    <div class="skel-line" style="width:88%"></div>
                </div>
            </section>
        `);
        parentEl.appendChild(card);
        return card;
    }

    function _renderEmpty(card, hint, reason) {
        const tableLabel = hint.schema ? `${hint.schema}.${hint.table}` : hint.table;
        const body = card.querySelector('.sample-preview-body');
        if (!body) return;
        body.innerHTML = `
            <div class="sample-preview-empty">
                <svg class="sample-preview-empty-ico" viewBox="0 0 24 24" aria-hidden="true">
                    <circle cx="12" cy="12" r="10" stroke="currentColor" stroke-width="1.8" fill="none"/>
                    <line x1="12" y1="8" x2="12" y2="13" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/>
                    <circle cx="12" cy="16.5" r="1" fill="currentColor"/>
                </svg>
                <p class="sample-preview-empty-msg">
                    <strong>${_esc(tableLabel)}</strong> için henüz örnek veri toplanmamış.
                </p>
                <p class="sample-preview-empty-hint">${_esc(reason || 'Yöneticinizden Veri Kaynakları → Örnek Veri Topla işlemini çalıştırmasını isteyin.')}</p>
            </div>
        `;
        card.classList.remove('sample-preview-loading');
        card.setAttribute('aria-busy', 'false');
    }

    function _renderData(card, hint, payload) {
        const body = card.querySelector('.sample-preview-body');
        if (!body) return;

        const columns = Array.isArray(payload.columns) ? payload.columns : [];
        const rows = Array.isArray(payload.rows) ? payload.rows : [];

        if (!rows.length) {
            _renderEmpty(card, hint, 'Cache boş döndü.');
            return;
        }

        // Türkçe etiket (varsa) başlığa ekle
        if (payload.business_name_tr) {
            const titleEl = card.querySelector('.sample-preview-title span');
            if (titleEl) {
                titleEl.textContent = 'Aday Tablo — ' + payload.business_name_tr;
            }
        }

        const colNames = columns.length ? columns.map((c) => c.name) : Object.keys(rows[0] || {});

        let html = '<div class="sample-preview-table-wrap"><table class="sample-preview-table"><thead><tr>';
        for (const c of colNames) {
            html += `<th scope="col">${_esc(c)}</th>`;
        }
        html += '</tr></thead><tbody>';
        for (const r of rows) {
            html += '<tr>';
            for (const c of colNames) {
                const v = r[c];
                const text = v == null ? '' : String(v);
                const truncated = text.length > 80 ? text.slice(0, 77) + '…' : text;
                html += `<td title="${_esc(text)}">${_esc(truncated)}</td>`;
            }
            html += '</tr>';
        }
        html += '</tbody></table></div>';

        // v3.28.7: footer — meta bilgi + "Sorguyu Özelleştir" CTA (drag-drop builder)
        const footer = `
            <div class="sample-preview-footer">
                <span class="sample-preview-meta">
                    ${rows.length} satır gösteriliyor
                    ${payload.row_count && payload.row_count > rows.length ? ` (cache: ${payload.row_count})` : ''}
                </span>
                ${payload.fetched_at ? `<span class="sample-preview-fetched" data-tooltip="Cache zamanı">⏱ ${_esc(payload.fetched_at.slice(0, 16).replace('T', ' '))}</span>` : ''}
                <button type="button"
                        class="sample-preview-customize-btn"
                        aria-label="Sorguyu özelleştir — drag-drop builder aç"
                        data-tooltip="Pre-execute drag-drop: kolon seç, filtre ekle, SQL önizle">
                    ✏️ Sorguyu Özelleştir
                </button>
            </div>
        `;

        body.innerHTML = html + footer;
        card.classList.remove('sample-preview-loading');
        card.setAttribute('aria-busy', 'false');

        // CTA → QueryBuilder.open
        const btn = card.querySelector('.sample-preview-customize-btn');
        if (btn && window.QueryBuilder && typeof window.QueryBuilder.open === 'function') {
            btn.addEventListener('click', () => _openQueryBuilder(card, hint, payload));
        } else if (btn) {
            // QueryBuilder yüklenmemişse butonu pasifleştir, sebebi tooltip'e yaz
            btn.disabled = true;
            btn.setAttribute('data-tooltip', 'Query Builder modülü yüklenmedi.');
        }
    }

    /**
     * Sample preview altına Query Builder render eder ve mevcut açık builder'ı kapatır.
     */
    function _openQueryBuilder(card, hint, payload) {
        if (!window.QueryBuilder || typeof window.QueryBuilder.open !== 'function') return;
        if (typeof window.QueryBuilder.close === 'function') {
            try { window.QueryBuilder.close(); } catch (_) { /* sessiz */ }
        }

        // QueryBuilder'ın yerleşeceği container — sample card'ın hemen altına
        let qbContainer = card.querySelector('.sample-preview-qb-container');
        if (!qbContainer) {
            qbContainer = document.createElement('div');
            qbContainer.className = 'sample-preview-qb-container';
            card.appendChild(qbContainer);
        } else {
            qbContainer.innerHTML = '';
        }

        // columns: backend [{name, type}] döner; defensif olarak string array'i de tolere et
        const rawCols = Array.isArray(payload.columns) ? payload.columns : [];
        const columns = rawCols.map((c) => (typeof c === 'string' ? { name: c, type: '' } : c))
            .filter((c) => c && c.name);

        window.QueryBuilder.open({
            parentEl: qbContainer,
            sourceId: hint.source_id,
            schema: hint.schema || null,
            table: hint.table,
            columns: columns,
            onSqlReady: (sql, params, warnings) => {
                // Phase 1: SQL'i preview panelinde göster (QueryBuilder kendi içinde gösterir).
                // Otomatik execute yapılmaz — kullanıcı niyet sahibi.
                if (warnings && warnings.length) {
                    console.info('[QueryBuilder] uyarılar:', warnings);
                }
            },
        });
    }

    /**
     * SSE event handler — dialog_chat.js bunu çağırır.
     * @param {HTMLElement} parentEl  Mesaj container
     * @param {Object} hint  {source_id, schema, table}
     */
    function renderSampleDataPreview(parentEl, hint) {
        if (!parentEl || !hint || !hint.source_id || !hint.table) return;

        // Aynı parent'a tekrar tekrar eklenmesin
        const existing = parentEl.querySelector('.sample-preview-card');
        if (existing) {
            return;
        }

        const card = _renderSkeleton(parentEl, hint);

        const params = new URLSearchParams({
            table: hint.table,
            limit: '5',
        });
        if (hint.schema) params.append('schema', hint.schema);

        // v3.34.0: vyraFetch — Auth + JSON + friendly error helper'da.
        // 404 grace path: vyraFetch throw eder, err.status===404 + err.data.detail.
        const path = `/data-sources/${encodeURIComponent(hint.source_id)}/samples?${params.toString()}`;
        window.vyraFetch(path)
            .then((data) => {
                _renderData(card, hint, data);
            })
            .catch((err) => {
                if (err && err.status === 404) {
                    _renderEmpty(card, hint, (err.data && err.data.detail) || undefined);
                    return;
                }
                console.warn('[SampleDataPreview] fetch hatası:', err && err.message);
                _renderEmpty(card, hint, 'Örnek veri yüklenemedi.');
            });
    }

    window.renderSampleDataPreview = renderSampleDataPreview;
})();


/* === assets/js/modules/query_builder.js === */
/**
 * VYRA Query Builder Module — v3.28.3 G4
 * =======================================
 * Pre-execute Drag-Drop Query Builder.
 *
 * Kullanıcı bir tablo seçtikten sonra:
 *   - Kolon chip'lerini SEÇİLDİ paneline drag-drop ile alır (sıra önemli)
 *   - Filtre satırı ekler (kolon + operatör + value)
 *   - Order by + limit ayarlar
 *   - "SQL Önizle" tıklayınca POST /api/query-state/preview
 *
 * SaaS / HEBE checklist:
 *   - role="application" (drag-drop kabı)
 *   - role="list" + role="listitem" alt kapsamlar
 *   - aria-grabbed (legacy) + aria-pressed
 *   - Tam keyboard alternatifi:
 *       Space: tutucu seç (grab) / bırak (drop)
 *       ArrowUp/Down: seçili kolonu yukarı/aşağı taşı (order)
 *       Enter: kolonu seçilenler panelinin sonuna ekle
 *       Escape: tutucudan vazgeç
 *   - data-tooltip ile yardım metni
 *   - aria-live="polite" status mesajı
 *
 * window.QueryBuilder = { open(opts), close() }
 *   opts:
 *     parentEl: HTMLElement       → component buraya inject edilir
 *     sourceId: number            → /api/query-state/preview body.source_id
 *     schema: string|null
 *     table: string
 *     columns: [{name, type}]     → ds_db_objects.columns_json içeriği
 *     dialect: 'postgresql'|...   → opsiyonel
 *     onSqlReady(sql, params, warnings) → SQL üretilince çağrılır
 */
(function () {
    'use strict';

    const ALLOWED_OPS = [
        { v: '=', label: '=' },
        { v: '!=', label: '≠' },
        { v: '<', label: '<' },
        { v: '<=', label: '≤' },
        { v: '>', label: '>' },
        { v: '>=', label: '≥' },
        { v: 'LIKE', label: 'LIKE' },
        { v: 'ILIKE', label: 'ILIKE' },
        { v: 'IS NULL', label: 'IS NULL' },
        { v: 'IS NOT NULL', label: 'IS NOT NULL' },
        { v: 'IN', label: 'IN (csv)' },
    ];

    /** Mevcut açık builder referansı (tek aktif builder) */
    let _activeRoot = null;

    function _el(tag, attrs = {}, ...children) {
        const e = document.createElement(tag);
        for (const [k, v] of Object.entries(attrs)) {
            if (k === 'class') e.className = v;
            else if (k === 'text') e.textContent = v;
            else if (k.startsWith('on') && typeof v === 'function') e.addEventListener(k.slice(2), v);
            else if (v !== undefined && v !== null) e.setAttribute(k, v);
        }
        for (const c of children) {
            if (c == null) continue;
            e.appendChild(typeof c === 'string' ? document.createTextNode(c) : c);
        }
        return e;
    }

    function _announce(root, msg) {
        const live = root.querySelector('.qb-live');
        if (live) live.textContent = msg;
    }

    function _renderAvailableColumn(col, state, root) {
        const chip = _el('button', {
            type: 'button',
            class: 'qb-col-chip',
            'data-col': col.name,
            'data-type': col.type || '',
            'aria-grabbed': 'false',
            'aria-pressed': 'false',
            'data-tooltip': `${col.name} (${col.type || '?'})`,
            title: `${col.name} (${col.type || '?'})`,
            text: col.name,
        });

        chip.addEventListener('click', () => {
            if (!state.selected.includes(col.name)) {
                state.selected.push(col.name);
                _renderSelected(state, root);
                _announce(root, `${col.name} seçildi`);
            }
        });

        chip.addEventListener('keydown', (e) => {
            if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                chip.click();
            }
        });

        // Drag start (mouse)
        chip.draggable = true;
        chip.addEventListener('dragstart', (e) => {
            e.dataTransfer.setData('text/plain', col.name);
            e.dataTransfer.effectAllowed = 'copy';
            chip.setAttribute('aria-grabbed', 'true');
        });
        chip.addEventListener('dragend', () => chip.setAttribute('aria-grabbed', 'false'));

        return chip;
    }

    function _renderSelected(state, root) {
        const list = root.querySelector('.qb-selected-list');
        list.innerHTML = '';
        if (state.selected.length === 0) {
            list.appendChild(_el('li', {
                class: 'qb-selected-empty',
                role: 'note',
                text: 'Henüz kolon seçilmedi. Kolon chip\'ine tıklayın veya buraya sürükleyin.',
            }));
            return;
        }
        state.selected.forEach((colName, idx) => {
            const li = _el('li', {
                class: 'qb-selected-item',
                role: 'listitem',
                tabindex: '0',
                'data-idx': String(idx),
                'aria-label': `${colName} — sıra ${idx + 1}`,
            });
            li.appendChild(_el('span', { class: 'qb-selected-handle', 'aria-hidden': 'true', text: '⋮⋮' }));
            li.appendChild(_el('span', { class: 'qb-selected-name', text: colName }));
            const rmBtn = _el('button', {
                type: 'button',
                class: 'qb-selected-remove',
                'aria-label': `${colName} kaldır`,
                title: 'Kaldır',
                text: '×',
            });
            rmBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                state.selected.splice(idx, 1);
                _renderSelected(state, root);
                _announce(root, `${colName} kaldırıldı`);
            });
            li.appendChild(rmBtn);

            // Keyboard: ArrowUp/Down = swap; Space = grab/drop toggle; Delete = remove
            li.addEventListener('keydown', (e) => {
                if (e.key === 'ArrowUp' && idx > 0) {
                    e.preventDefault();
                    [state.selected[idx - 1], state.selected[idx]] = [state.selected[idx], state.selected[idx - 1]];
                    _renderSelected(state, root);
                    const items = list.querySelectorAll('.qb-selected-item');
                    if (items[idx - 1]) items[idx - 1].focus();
                    _announce(root, `${colName} yukarı taşındı`);
                } else if (e.key === 'ArrowDown' && idx < state.selected.length - 1) {
                    e.preventDefault();
                    [state.selected[idx + 1], state.selected[idx]] = [state.selected[idx], state.selected[idx + 1]];
                    _renderSelected(state, root);
                    const items = list.querySelectorAll('.qb-selected-item');
                    if (items[idx + 1]) items[idx + 1].focus();
                    _announce(root, `${colName} aşağı taşındı`);
                } else if (e.key === 'Delete' || e.key === 'Backspace') {
                    e.preventDefault();
                    rmBtn.click();
                } else if (e.key === 'Escape') {
                    li.blur();
                }
            });
            list.appendChild(li);
        });
    }

    function _renderFilters(state, root) {
        const wrap = root.querySelector('.qb-filters-list');
        wrap.innerHTML = '';
        state.filters.forEach((f, i) => {
            const row = _el('div', { class: 'qb-filter-row', role: 'group', 'aria-label': `Filtre ${i + 1}` });

            // Column select
            const colSel = _el('select', { class: 'qb-filter-col', 'aria-label': 'Kolon' });
            colSel.appendChild(_el('option', { value: '', text: '— kolon —' }));
            state.columns.forEach(c => {
                const opt = _el('option', { value: c.name, text: c.name });
                if (c.name === f.column) opt.selected = true;
                colSel.appendChild(opt);
            });
            colSel.addEventListener('change', () => { f.column = colSel.value; });

            // Op select
            const opSel = _el('select', { class: 'qb-filter-op', 'aria-label': 'Operatör' });
            ALLOWED_OPS.forEach(o => {
                const opt = _el('option', { value: o.v, text: o.label });
                if (o.v === f.op) opt.selected = true;
                opSel.appendChild(opt);
            });
            opSel.addEventListener('change', () => {
                f.op = opSel.value;
                _renderFilters(state, root);
            });

            // Value input (IS NULL/IS NOT NULL → gizli)
            const isNullOp = f.op === 'IS NULL' || f.op === 'IS NOT NULL';
            const valInput = _el('input', {
                type: 'text',
                class: 'qb-filter-val',
                'aria-label': 'Değer',
                placeholder: f.op === 'IN' ? 'a,b,c' : 'değer',
                value: f.value != null ? String(f.value) : '',
            });
            if (isNullOp) valInput.style.visibility = 'hidden';
            valInput.addEventListener('input', () => { f.value = valInput.value; });

            // Remove
            const rmBtn = _el('button', {
                type: 'button',
                class: 'qb-filter-remove',
                'aria-label': `Filtre ${i + 1} kaldır`,
                title: 'Kaldır',
                text: '×',
            });
            rmBtn.addEventListener('click', () => {
                state.filters.splice(i, 1);
                _renderFilters(state, root);
            });

            row.appendChild(colSel);
            row.appendChild(opSel);
            row.appendChild(valInput);
            row.appendChild(rmBtn);
            wrap.appendChild(row);
        });
    }

    function _coerceFilters(filters) {
        return filters
            .filter(f => f.column && f.op)
            .map(f => {
                if (f.op === 'IS NULL' || f.op === 'IS NOT NULL') {
                    return { column: f.column, op: f.op };
                }
                if (f.op === 'IN') {
                    const vals = String(f.value || '')
                        .split(',').map(s => s.trim()).filter(Boolean);
                    return { column: f.column, op: 'IN', value: vals };
                }
                let v = f.value;
                if (v != null && /^-?\d+(\.\d+)?$/.test(String(v).trim())) {
                    v = Number(v);
                }
                return { column: f.column, op: f.op, value: v };
            });
    }

    async function _fetchPreview(state, root) {
        const statusEl = root.querySelector('.qb-status');
        const sqlBox = root.querySelector('.qb-sql-output');
        statusEl.textContent = 'Sorgu inşa ediliyor...';
        statusEl.setAttribute('aria-busy', 'true');
        sqlBox.textContent = '';

        const body = {
            source_id: state.sourceId || null,
            schema: state.schema || null,
            table: state.table,
            dialect: state.dialect || null,
            selected_columns: state.selected,
            filters: _coerceFilters(state.filters),
            order_by: state.orderColumn ? {
                column: state.orderColumn,
                direction: state.orderDir || 'ASC',
            } : null,
            limit: Number(state.limit) || 100,
        };

        try {
            // v3.34.0: vyraFetch — auth header + JSON parse + Türkçe error mesajı helper'dan
            let data;
            try {
                data = await window.vyraFetch('/query-state/preview', { method: 'POST', body });
            } catch (httpErr) {
                statusEl.removeAttribute('aria-busy');
                const fallback = (httpErr && httpErr.data && (httpErr.data.detail || (httpErr.data.warnings || []).join('; '))) || (httpErr && httpErr.message) || 'Bilinmeyen hata';
                statusEl.textContent = `Hata: ${fallback}`;
                statusEl.classList.add('qb-status-error');
                return;
            }
            statusEl.removeAttribute('aria-busy');

            if (!data.valid) {
                const errs = (data.warnings || [data.detail || 'Bilinmeyen hata']).join('; ');
                statusEl.textContent = `Hata: ${errs}`;
                statusEl.classList.add('qb-status-error');
                return;
            }
            statusEl.classList.remove('qb-status-error');
            statusEl.textContent = data.warnings && data.warnings.length
                ? `Uyarılar: ${data.warnings.join('; ')}`
                : 'SQL hazır.';
            // v3.33.0: display_sql tercih (backend `%s` placeholder'ları
            // _inline_literal whitelist'iyle güvenli inline etti). display_sql
            // None ise (güvensiz tip) ham sql fallback'i basılır.
            sqlBox.textContent = data.display_sql || data.sql || '';
            _announce(root, 'SQL üretildi');

            // v3.32.0: SQL'i state'e cache'le ve action butonlarını aktif et.
            // NOT: execute path backend'de inline ediyor, bu yüzden state.lastSql
            // hâlâ ham `%s`'li sürüm — execute body re-build ediliyor zaten.
            state.lastSql = data.sql || '';
            state.lastParams = data.params || [];
            // v3.35.0: "Asistana Gönder" panel'deki display_sql ile aynı metni
            // göndersin (param'lar inline). Aksi halde chat'e `%s`'li ham SQL
            // gidiyor ve asistan değer eksik diye reddediyor.
            state.lastDisplaySql = data.display_sql || data.sql || '';
            _enableActionButtons(root, !!state.lastSql);

            if (typeof state.onSqlReady === 'function') {
                state.onSqlReady(data.sql, data.params || [], data.warnings || []);
            }
        } catch (err) {
            statusEl.removeAttribute('aria-busy');
            statusEl.textContent = `Ağ hatası: ${err.message}`;
            statusEl.classList.add('qb-status-error');
        }
    }

    // ── v3.32.0: Action helpers ────────────────────────────────────────

    function _enableActionButtons(root, enabled) {
        for (const cls of ['.qb-copy-btn', '.qb-exec-btn', '.qb-send-btn']) {
            const btn = root.querySelector(cls);
            if (!btn) continue;
            if (enabled) btn.removeAttribute('disabled');
            else btn.setAttribute('disabled', 'true');
        }
    }

    async function _copySql(state, root) {
        const statusEl = root.querySelector('.qb-status');
        if (!state.lastSql) {
            statusEl.textContent = 'Önce "SQL Önizle" tıklayın.';
            return;
        }
        try {
            // v3.35.x F2: kullanıcı "Üretilen SQL" panelinde gördüğü display_sql'i
            // bekliyor (literaller inlined); state.lastSql ise %s placeholder'lı
            // raw SQL. lastDisplaySql v3.35.0'da cache'lendi — fallback-safe.
            const sqlToCopy = state.lastDisplaySql || state.lastSql;
            if (navigator.clipboard && navigator.clipboard.writeText) {
                await navigator.clipboard.writeText(sqlToCopy);
            } else {
                // Fallback: textarea trick
                const ta = document.createElement('textarea');
                ta.value = sqlToCopy;
                ta.setAttribute('readonly', '');
                ta.style.position = 'absolute';
                ta.style.left = '-9999px';
                document.body.appendChild(ta);
                ta.select();
                document.execCommand('copy');
                document.body.removeChild(ta);
            }
            statusEl.classList.remove('qb-status-error');
            statusEl.textContent = 'SQL panoya kopyalandı (görüntülenen sürüm).';
            if (window.showToast) window.showToast('SQL panoya kopyalandı', 'success');
            _announce(root, 'SQL panoya kopyalandı');
        } catch (err) {
            statusEl.classList.add('qb-status-error');
            statusEl.textContent = `Kopyalama hatası: ${err.message}`;
        }
    }

    async function _executeSql(state, root) {
        const statusEl = root.querySelector('.qb-status');
        const resultSection = root.querySelector('.qb-result-section');
        const resultMeta = root.querySelector('.qb-result-meta');
        const resultBody = root.querySelector('.qb-result-body');

        if (!state.lastSql) {
            statusEl.textContent = 'Önce "SQL Önizle" tıklayın.';
            return;
        }
        if (!state.sourceId) {
            statusEl.classList.add('qb-status-error');
            statusEl.textContent = 'source_id eksik — execute mümkün değil.';
            return;
        }

        // execute=true ile aynı preview endpoint'ini çağırıyoruz; backend
        // params'ı strict whitelist ile inline edip SafeSQLExecutor üzerinden
        // 5sn timeout + 100 satır cap ile çalıştırır.
        const body = {
            source_id: state.sourceId,
            schema: state.schema || null,
            table: state.table,
            dialect: state.dialect || null,
            selected_columns: state.selected,
            filters: _coerceFilters(state.filters),
            order_by: state.orderColumn ? {
                column: state.orderColumn,
                direction: state.orderDir || 'ASC',
            } : null,
            limit: Number(state.limit) || 100,
            execute: true,
        };

        statusEl.textContent = 'Çalıştırılıyor (5sn timeout)...';
        statusEl.setAttribute('aria-busy', 'true');
        statusEl.classList.remove('qb-status-error');
        resultSection.setAttribute('hidden', 'hidden');
        resultBody.innerHTML = '';
        resultMeta.textContent = '';

        try {
            // v3.34.0: vyraFetch — execute=true preview ucu
            let data;
            try {
                data = await window.vyraFetch('/query-state/preview', { method: 'POST', body });
            } catch (httpErr) {
                statusEl.removeAttribute('aria-busy');
                statusEl.classList.add('qb-status-error');
                const detail = (httpErr && httpErr.data && (httpErr.data.detail || httpErr.data.execute_error)) || (httpErr && httpErr.message) || 'Hata';
                const stat = httpErr && httpErr.status ? `HTTP ${httpErr.status}: ` : '';
                statusEl.textContent = `${stat}${detail}`;
                return;
            }
            statusEl.removeAttribute('aria-busy');
            if (data.success === false) {
                resultSection.removeAttribute('hidden');
                resultMeta.textContent = '⚠ Çalıştırma hatası';
                resultBody.innerHTML = `<div class="qb-result-error">${_escHtml(data.execute_error || 'Bilinmeyen hata')}</div>`;
                statusEl.classList.add('qb-status-error');
                statusEl.textContent = 'Sorgu hata döndürdü — detay için sonuç alanına bakın.';
                return;
            }
            // Başarılı — sonucu render et
            const rows = Array.isArray(data.rows) ? data.rows : [];
            const cols = Array.isArray(data.columns) && data.columns.length
                ? data.columns
                : (rows[0] && typeof rows[0] === 'object' ? Object.keys(rows[0]) : []);
            resultSection.removeAttribute('hidden');
            resultMeta.textContent = `${rows.length} satır`
                + (data.row_count && data.row_count !== rows.length ? ` (toplam: ${data.row_count})` : '')
                + (data.truncated ? ' • cap uygulandı' : '')
                + (data.elapsed_ms ? ` • ${Math.round(data.elapsed_ms)}ms` : '');
            resultBody.innerHTML = _renderResultTable(cols, rows);
            statusEl.textContent = 'Sorgu çalıştırıldı.';
            if (window.showToast) window.showToast(`Sorgu başarılı (${rows.length} satır)`, 'success');
            _announce(root, `Sorgu çalıştırıldı, ${rows.length} satır`);
        } catch (err) {
            statusEl.removeAttribute('aria-busy');
            statusEl.classList.add('qb-status-error');
            statusEl.textContent = `Ağ hatası: ${err.message}`;
        }
    }

    // v3.34.1 BUG-5: form değişince lastSql'i geçersiz say (stale-state guard).
    // Delegated listener `open()` mount sonrasında root'a takılıyor; bu helper
    // hem state'i temizler hem action butonlarını disable eder hem de UX uyarısı basar.
    function _invalidateLastSql(state, root, reason) {
        if (!state.lastSql) return; // zaten geçersiz — tekrar mesaj basma
        state.lastSql = '';
        state.lastParams = [];
        state.lastDisplaySql = '';
        _enableActionButtons(root, false);
        const statusEl = root.querySelector('.qb-status');
        if (statusEl) {
            statusEl.classList.remove('qb-status-error');
            statusEl.textContent = reason || 'Form değişti — SQL\'i yeniden önizleyin.';
        }
        _announce(root, 'Form değişti, SQL geçersiz; yeniden önizleyin');
    }

    function _sendSqlToChat(state, root) {
        const statusEl = root.querySelector('.qb-status');
        if (!state.lastSql) {
            statusEl.textContent = 'Önce "SQL Önizle" tıklayın (form değişmişse yeniden).';
            return;
        }
        const inp = document.getElementById('dialogInput');
        if (!inp) {
            statusEl.classList.add('qb-status-error');
            statusEl.textContent = 'Sohbet kutusu bulunamadı.';
            return;
        }
        // v3.35.0: "Üretilen SQL" panel'i display_sql gösteriyor (param inline).
        // Önceden state.lastSql (ham %s'li sürüm) chat'e gidiyordu; asistan
        // tarafında "değerler eksik" hatası oluşuyordu. Şimdi panel ile bire bir
        // aynı metni gönderiyoruz.
        const sqlToSend = state.lastDisplaySql || state.lastSql;
        const prefix = `Şu SQL'i çalıştırıp sonucunu açıklar mısın:\n\`\`\`sql\n${sqlToSend}\n\`\`\``;
        inp.value = prefix;
        inp.focus();
        // textarea ise yüksekliği güncellesin
        try { inp.dispatchEvent(new Event('input', { bubbles: true })); } catch (_) {}
        statusEl.classList.remove('qb-status-error');
        statusEl.textContent = 'SQL sohbet kutusuna kopyalandı — göndermek için Enter\'a basın.';
        if (window.showToast) window.showToast('SQL sohbet kutusuna yapıştırıldı', 'info');
        _announce(root, 'SQL sohbet kutusuna kopyalandı');
    }

    function _escHtml(s) {
        return String(s == null ? '' : s)
            .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
    }

    function _renderResultTable(cols, rows) {
        if (!rows || !rows.length) {
            return '<div class="qb-result-empty">Sonuç boş.</div>';
        }
        const colList = (cols && cols.length) ? cols : Object.keys(rows[0] || {});
        let html = '<div class="qb-result-table-wrap"><table class="qb-result-table"><thead><tr>';
        for (const c of colList) html += `<th>${_escHtml(c)}</th>`;
        html += '</tr></thead><tbody>';
        for (const r of rows) {
            html += '<tr>';
            for (const c of colList) {
                const v = r && typeof r === 'object' ? r[c] : null;
                const txt = v == null ? '' : String(v);
                const trunc = txt.length > 120 ? txt.slice(0, 117) + '…' : txt;
                html += `<td title="${_escHtml(txt)}">${_escHtml(trunc)}</td>`;
            }
            html += '</tr>';
        }
        html += '</tbody></table></div>';
        return html;
    }

    function open(opts) {
        if (!opts || !opts.parentEl || !opts.table) {
            console.warn('[query_builder] parentEl ve table zorunlu');
            return null;
        }

        // Tekil aktif builder — eskiyi kapat
        if (_activeRoot && _activeRoot.parentNode) {
            _activeRoot.parentNode.removeChild(_activeRoot);
        }

        const state = {
            sourceId: opts.sourceId,
            schema: opts.schema || null,
            table: opts.table,
            dialect: opts.dialect || null,
            columns: Array.isArray(opts.columns) ? opts.columns.filter(c => c && c.name) : [],
            selected: [],
            filters: [],
            orderColumn: '',
            orderDir: 'ASC',
            limit: 100,
            onSqlReady: opts.onSqlReady,
        };

        const titleId = `qb-title-${Date.now()}`;

        const root = _el('section', {
            class: 'qb-card',
            role: 'application',
            'aria-labelledby': titleId,
            'aria-roledescription': 'sorgu inşa aracı',
        });

        // Header
        const header = _el('header', { class: 'qb-header' });
        header.appendChild(_el('h3', {
            id: titleId,
            class: 'qb-title',
            text: `Query Builder — ${opts.schema ? opts.schema + '.' : ''}${opts.table}`,
        }));
        const closeBtn = _el('button', {
            type: 'button',
            class: 'qb-close',
            'aria-label': 'Kapat',
            title: 'Kapat (Esc)',
            text: '×',
        });
        closeBtn.addEventListener('click', close);
        header.appendChild(closeBtn);
        root.appendChild(header);

        // Available columns
        const availSection = _el('div', { class: 'qb-section qb-available-section' });
        availSection.appendChild(_el('h4', { class: 'qb-section-title', text: 'Kolonlar' }));
        availSection.appendChild(_el('p', {
            class: 'qb-section-hint',
            text: 'Tıklayın veya seçildi paneline sürükleyin.',
        }));
        const availList = _el('div', {
            class: 'qb-col-list',
            role: 'list',
            'aria-label': 'Mevcut kolonlar',
        });
        state.columns.forEach(c => availList.appendChild(_renderAvailableColumn(c, state, root)));
        if (state.columns.length === 0) {
            availList.appendChild(_el('span', {
                class: 'qb-empty-inline',
                text: 'Bu tabloda kolon bilgisi yok.',
            }));
        }
        availSection.appendChild(availList);
        root.appendChild(availSection);

        // Selected (drag target)
        const selSection = _el('div', { class: 'qb-section qb-selected-section' });
        selSection.appendChild(_el('h4', { class: 'qb-section-title', text: 'Seçilen kolonlar (sıra korunur)' }));
        const selList = _el('ol', {
            class: 'qb-selected-list',
            role: 'list',
            'aria-label': 'Seçilen kolonlar — Ok tuşları ile sıralayın, Delete ile kaldırın',
        });
        selSection.appendChild(selList);

        // Drop zone behaviour
        selList.addEventListener('dragover', (e) => {
            e.preventDefault();
            e.dataTransfer.dropEffect = 'copy';
            selList.classList.add('qb-drop-active');
        });
        selList.addEventListener('dragleave', () => selList.classList.remove('qb-drop-active'));
        selList.addEventListener('drop', (e) => {
            e.preventDefault();
            selList.classList.remove('qb-drop-active');
            const col = e.dataTransfer.getData('text/plain');
            if (col && !state.selected.includes(col)) {
                state.selected.push(col);
                _renderSelected(state, root);
                _announce(root, `${col} eklendi`);
            }
        });
        root.appendChild(selSection);

        // Filters
        const filterSection = _el('div', { class: 'qb-section qb-filter-section' });
        filterSection.appendChild(_el('h4', { class: 'qb-section-title', text: 'Filtreler (WHERE)' }));
        const filtersList = _el('div', { class: 'qb-filters-list' });
        filterSection.appendChild(filtersList);
        const addFilterBtn = _el('button', {
            type: 'button',
            class: 'qb-add-filter',
            text: '+ Filtre ekle',
        });
        addFilterBtn.addEventListener('click', () => {
            state.filters.push({ column: '', op: '=', value: '' });
            _renderFilters(state, root);
        });
        filterSection.appendChild(addFilterBtn);
        root.appendChild(filterSection);

        // Order/Limit
        const orderSection = _el('div', { class: 'qb-section qb-order-section' });
        orderSection.appendChild(_el('h4', { class: 'qb-section-title', text: 'Sıralama & Limit' }));
        const orderRow = _el('div', { class: 'qb-order-row' });

        const orderColSel = _el('select', { class: 'qb-order-col', 'aria-label': 'Sırala' });
        orderColSel.appendChild(_el('option', { value: '', text: '— sıra yok —' }));
        state.columns.forEach(c => orderColSel.appendChild(_el('option', { value: c.name, text: c.name })));
        orderColSel.addEventListener('change', () => { state.orderColumn = orderColSel.value; });

        const dirSel = _el('select', { class: 'qb-order-dir', 'aria-label': 'Yön' });
        ['ASC', 'DESC'].forEach(d => dirSel.appendChild(_el('option', { value: d, text: d })));
        dirSel.addEventListener('change', () => { state.orderDir = dirSel.value; });

        const limitInput = _el('input', {
            type: 'number',
            class: 'qb-limit',
            'aria-label': 'Limit',
            min: '1',
            max: '10000',
            value: '100',
        });
        limitInput.addEventListener('input', () => { state.limit = Number(limitInput.value) || 100; });

        orderRow.appendChild(orderColSel);
        orderRow.appendChild(dirSel);
        orderRow.appendChild(_el('label', { class: 'qb-limit-label', text: 'Limit:' }));
        orderRow.appendChild(limitInput);
        orderSection.appendChild(orderRow);
        root.appendChild(orderSection);

        // Action bar
        const actions = _el('div', { class: 'qb-actions' });
        const previewBtn = _el('button', {
            type: 'button',
            class: 'qb-preview-btn',
            text: 'SQL Önizle',
            'data-tooltip': 'Parametrize SELECT SQL üretir (yürütmez)',
        });
        previewBtn.addEventListener('click', () => _fetchPreview(state, root));
        actions.appendChild(previewBtn);

        // v3.32.0: Kopyala
        const copyBtn = _el('button', {
            type: 'button',
            class: 'qb-copy-btn',
            text: '📋 Kopyala',
            disabled: 'true',
            'aria-label': 'SQL\'i panoya kopyala',
            'data-tooltip': 'Üretilen SQL\'i panoya kopyalar (dış DB tool için)',
        });
        copyBtn.addEventListener('click', () => _copySql(state, root));
        actions.appendChild(copyBtn);

        // v3.32.0: Çalıştır
        const execBtn = _el('button', {
            type: 'button',
            class: 'qb-exec-btn',
            text: '▶️ Çalıştır',
            disabled: 'true',
            'aria-label': 'SQL\'i veritabanında çalıştır',
            'data-tooltip': '5sn timeout, 100 satır cap ile yürütür',
        });
        execBtn.addEventListener('click', () => _executeSql(state, root));
        actions.appendChild(execBtn);

        // v3.32.0: Asistana Gönder
        const sendBtn = _el('button', {
            type: 'button',
            class: 'qb-send-btn',
            text: '💬 Asistana Gönder',
            disabled: 'true',
            'aria-label': 'SQL\'i sohbet kutusuna gönder',
            'data-tooltip': 'SQL\'i sohbet kutusuna yapıştırır — manuel gönderirsin',
        });
        sendBtn.addEventListener('click', () => _sendSqlToChat(state, root));
        actions.appendChild(sendBtn);

        root.appendChild(actions);

        // SQL output
        const sqlSection = _el('div', { class: 'qb-section qb-sql-section' });
        sqlSection.appendChild(_el('h4', { class: 'qb-section-title', text: 'Üretilen SQL' }));
        const sqlBox = _el('pre', {
            class: 'qb-sql-output',
            tabindex: '0',
            'aria-label': 'Üretilen SQL (parametrize)',
        });
        sqlSection.appendChild(sqlBox);
        root.appendChild(sqlSection);

        // v3.32.0: Execute sonucu (gizli, dolduğunda görünür)
        const resultSection = _el('div', {
            class: 'qb-section qb-result-section',
            hidden: 'hidden',
            'aria-label': 'SQL çalıştırma sonucu',
        });
        resultSection.appendChild(_el('h4', { class: 'qb-section-title', text: 'Sonuç' }));
        resultSection.appendChild(_el('div', { class: 'qb-result-meta', role: 'status', 'aria-live': 'polite' }));
        resultSection.appendChild(_el('div', { class: 'qb-result-body' }));
        root.appendChild(resultSection);

        // Live region + status
        root.appendChild(_el('div', {
            class: 'qb-live',
            role: 'status',
            'aria-live': 'polite',
            'aria-atomic': 'true',
        }));
        root.appendChild(_el('div', { class: 'qb-status', role: 'status', 'aria-live': 'polite' }));

        // Mount
        opts.parentEl.appendChild(root);
        _activeRoot = root;
        _renderSelected(state, root);

        // v3.34.1 BUG-5: stale-state invalidation — WHERE/ORDER/LIMIT/SELECT
        // değişimleri lastSql'i geçersiz kılar. Delegated listener: yeni
        // eklenen filter row'ları da otomatik kapsar (re-bind gerekmez).
        // Sadece form alanlarını dinle; SQL output / sonuç kutusu hariç.
        const _isFormControl = (el) => {
            if (!el || !el.classList) return false;
            return el.classList.contains('qb-filter-col')
                || el.classList.contains('qb-filter-op')
                || el.classList.contains('qb-filter-val')
                || el.classList.contains('qb-order-col')
                || el.classList.contains('qb-order-dir')
                || el.classList.contains('qb-limit');
        };
        const _onFormMutate = (e) => {
            if (_isFormControl(e.target)) _invalidateLastSql(state, root);
        };
        root.addEventListener('input', _onFormMutate);
        root.addEventListener('change', _onFormMutate);
        // SELECT kolon ekle/çıkar + filtre ekle/çıkar click delegasyonu.
        // (Reorder klavye ile yapılıyor — keydown ayrıca yakalanır.)
        root.addEventListener('click', (e) => {
            const t = e.target;
            if (!t || !t.classList) return;
            if (t.classList.contains('qb-col-chip')
                || t.classList.contains('qb-selected-remove')
                || t.classList.contains('qb-add-filter')
                || t.classList.contains('qb-filter-remove')) {
                _invalidateLastSql(state, root);
            }
        });
        // Seçili kolon listesinde ArrowUp/ArrowDown → reorder.
        root.addEventListener('keydown', (e) => {
            const t = e.target;
            if (!t || !t.classList) return;
            if (!t.classList.contains('qb-selected-handle')) return;
            if (e.key === 'ArrowUp' || e.key === 'ArrowDown') {
                _invalidateLastSql(state, root);
            }
        });

        // Global keyboard: Esc → close
        const escHandler = (e) => {
            if (e.key === 'Escape' && _activeRoot === root) {
                close();
            }
        };
        root.addEventListener('keydown', escHandler);

        // Focus first chip for keyboard users
        setTimeout(() => {
            const firstChip = root.querySelector('.qb-col-chip');
            if (firstChip) firstChip.focus();
        }, 50);

        return { root, state };
    }

    function close() {
        if (_activeRoot && _activeRoot.parentNode) {
            _activeRoot.parentNode.removeChild(_activeRoot);
        }
        _activeRoot = null;
    }

    window.QueryBuilder = { open, close };
})();


