    // ============================================
    // Öğrenme Sonuçları Popup (ML QA Çiftleri)
    // ============================================

    async function showLearningResults(sourceId) {
        const existing = document.getElementById('dsLearningResultsModal');
        if (existing) existing.remove();

        // Pagination ve arama state'i
        const _lrState = {
            page: 1,
            pageSize: 30,
            search: '',
            debounceTimer: null
        };

        const modal = document.createElement('div');
        modal.id = 'dsLearningResultsModal';
        modal.className = 'ds-wizard-overlay';
        modal.innerHTML = `
            <div class="ds-wizard-modal ds-details-modal ds-lr-modal">
                <div class="ds-wizard-header">
                    <div class="ds-wizard-title">
                        <i class="fa-solid fa-graduation-cap"></i>
                        <span>ML Öğrenme Sonuçları — ${_escapeHtml(_currentSourceName || '')}</span>
                    </div>
                    <button class="ds-wizard-close" id="dsLrClose">
                        <i class="fa-solid fa-times"></i>
                    </button>
                </div>
                <div class="ds-lr-job-filter" id="dsLrJobFilter">
                    <label><i class="fa-solid fa-clock-rotate-left"></i> İş Geçmişi:</label>
                    <select id="dsLrJobSelect" class="ds-form-select ds-lr-job-select">
                        <option value="">Tüm İşler</option>
                    </select>
                </div>
                <div class="ds-lr-toolbar" id="dsLrToolbar">
                    <div class="ds-lr-search-wrap">
                        <i class="fa-solid fa-search ds-lr-search-icon"></i>
                        <input type="text" id="dsLrSearchInput" class="ds-lr-search-input" placeholder="Tablo adı veya içerik ara..." autocomplete="off">
                    </div>
                </div>
                <div class="ds-lr-summary" id="dsLrSummary"></div>
                <div class="ds-wizard-body ds-details-body ds-lr-body" id="dsLrBody">
                    <div class="ds-lr-loading"><i class="fa-solid fa-spinner fa-spin"></i> Yükleniyor...</div>
                </div>
                <div class="ds-lr-pagination" id="dsLrPagination"></div>
            </div>
        `;

        document.body.appendChild(modal);
        requestAnimationFrame(() => modal.classList.add('active'));

        let _pollInterval = null;
        const closeLr = () => { 
            if (_pollInterval) clearInterval(_pollInterval);
            if (_lrState.debounceTimer) clearTimeout(_lrState.debounceTimer);
            modal.classList.remove('active'); 
            setTimeout(() => modal.remove(), 300); 
        };
        document.getElementById('dsLrClose').addEventListener('click', closeLr);
        document.addEventListener('keydown', function escLr(e) {
            if (e.key === 'Escape') { closeLr(); document.removeEventListener('keydown', escLr); }
        });

        // Mevcut sayfayı yükle
        async function loadCurrentPage(isPolling) {
            const jobId = document.getElementById('dsLrJobSelect').value || null;
            const offset = (_lrState.page - 1) * _lrState.pageSize;
            await _loadLearningResults(sourceId, 'schema_record', jobId, isPolling, _lrState.pageSize, offset, _lrState.search, _lrState, _renderPagination);
        }

        // Pagination render
        function _renderPagination(paginationData) {
            const container = document.getElementById('dsLrPagination');
            if (!container) return;

            const { page, total_pages, total_filtered } = paginationData;
            if (total_pages <= 1) {
                container.innerHTML = '';
                return;
            }

            const maxVisible = 5;
            let startPage = Math.max(1, page - Math.floor(maxVisible / 2));
            let endPage = Math.min(total_pages, startPage + maxVisible - 1);
            if (endPage - startPage < maxVisible - 1) {
                startPage = Math.max(1, endPage - maxVisible + 1);
            }

            let html = '<div class="ds-lr-pagination-inner">';
            html += `<button class="ds-lr-page-btn" data-page="1" ${page === 1 ? 'disabled' : ''}><i class="fa-solid fa-angles-left"></i></button>`;
            html += `<button class="ds-lr-page-btn" data-page="${page - 1}" ${page === 1 ? 'disabled' : ''}><i class="fa-solid fa-angle-left"></i></button>`;

            for (let i = startPage; i <= endPage; i++) {
                html += `<button class="ds-lr-page-btn ${i === page ? 'active' : ''}" data-page="${i}">${i}</button>`;
            }

            html += `<button class="ds-lr-page-btn" data-page="${page + 1}" ${page === total_pages ? 'disabled' : ''}><i class="fa-solid fa-angle-right"></i></button>`;
            html += `<button class="ds-lr-page-btn" data-page="${total_pages}" ${page === total_pages ? 'disabled' : ''}><i class="fa-solid fa-angles-right"></i></button>`;
            html += `<span class="ds-lr-page-info">${total_filtered} kayıt</span>`;
            html += '</div>';

            container.innerHTML = html;

            // Page buton event'leri
            container.querySelectorAll('.ds-lr-page-btn:not([disabled])').forEach(btn => {
                btn.addEventListener('click', () => {
                    const targetPage = parseInt(btn.dataset.page);
                    if (targetPage && targetPage !== _lrState.page) {
                        _lrState.page = targetPage;
                        loadCurrentPage(false);
                    }
                });
            });
        }

        // İş geçmişi dropdown'ını doldur
        try {
            const statsData = await apiCall(`/${sourceId}/job-result-stats`);
            const select = document.getElementById('dsLrJobSelect');
            if (statsData.stats && statsData.stats.length > 0) {
                statsData.stats.forEach(s => {
                    const date = s.started_at ? _formatDateTime(s.started_at) : '?';
                    const opt = document.createElement('option');
                    opt.value = s.job_id;
                    opt.textContent = `${date} — ${s.result_count} QA (${s.type_count} tip)`;
                    select.appendChild(opt);
                });
            }
        } catch (e) { /* dropdown opsiyonel */ }

        // Dropdown seçimi
        document.getElementById('dsLrJobSelect').addEventListener('change', () => {
            _lrState.page = 1;
            loadCurrentPage(false);
        });

        // Arama input'u (debounce ile)
        document.getElementById('dsLrSearchInput').addEventListener('input', (e) => {
            if (_lrState.debounceTimer) clearTimeout(_lrState.debounceTimer);
            _lrState.debounceTimer = setTimeout(() => {
                _lrState.search = e.target.value.trim();
                _lrState.page = 1;
                loadCurrentPage(false);
            }, 400);
        });

        // Auto Refresh (Polling)
        async function fetchInitialAndPoll() {
            await loadCurrentPage(false);
            try {
                const check = await apiCall(`/${sourceId}/check-running-job`);
                if (check.has_running) {
                    _pollInterval = setInterval(() => {
                        loadCurrentPage(true);
                    }, 5000);
                }
            } catch(e) {}
        }

        fetchInitialAndPoll();
    }

    async function _loadLearningResults(sourceId, contentType, jobId, isPolling, pageSize, offset, search, stateRef, renderPaginationFn) {
        const body = document.getElementById('dsLrBody');
        const summary = document.getElementById('dsLrSummary');
        if (!body) return;

        if (!isPolling) {
            body.innerHTML = '<div class="ds-lr-loading"><i class="fa-solid fa-spinner fa-spin"></i> Yükleniyor...</div>';
        }

        try {
            let url = `/${sourceId}/learning-results?limit=${pageSize}&offset=${offset}`;
            if (contentType) url += `&content_type=${contentType}`;
            if (jobId) url += `&job_id=${jobId}`;
            if (search) url += `&search=${encodeURIComponent(search)}`;
            const data = await apiCall(url);
            const results = data.results || [];
            const typeCounts = data.type_counts || {};
            const totalAll = data.total || 0;
            const totalFiltered = data.total_filtered || 0;
            const currentPage = data.page || 1;
            const totalPages = data.total_pages || 1;

            // Özet bilgi
            const typeLabels = {
                'schema_record': 'Şema Kaydı',
            };

            let summaryContent = `
                <div class="ds-lr-summary-inner">
                    <div class="ds-lr-stat"><span class="ds-lr-stat-num">${totalAll}</span><span class="ds-lr-stat-label">Toplam Kayıt</span></div>
                    ${Object.entries(typeCounts).map(([t, c]) =>
                        `<div class="ds-lr-stat"><span class="ds-lr-stat-num">${c}</span><span class="ds-lr-stat-label">${typeLabels[t] || t}</span></div>`
                    ).join('')}
            `;
            if (search && totalFiltered !== totalAll) {
                summaryContent += `<div class="ds-lr-stat ds-lr-stat-filtered"><span class="ds-lr-stat-num">${totalFiltered}</span><span class="ds-lr-stat-label">Filtre Sonucu</span></div>`;
            }
            summaryContent += '</div>';
            summary.innerHTML = summaryContent;

            if (results.length === 0) {
                const emptyMsg = search ? 
                    `"${_escapeHtml(search)}" araması için sonuç bulunamadı.` :
                    'Henüz öğrenme sonucu bulunmuyor. Önce tabloları onaylayıp "Onaylıları Öğren" butonunu kullanın.';
                body.innerHTML = `<div class="ds-lr-loading">${emptyMsg}</div>`;
                if (renderPaginationFn) renderPaginationFn({ page: 1, total_pages: 0, total_filtered: 0 });
                return;
            }

            body.innerHTML = results.map((r, idx) => {
                const typeLabel = typeLabels[r.content_type] || r.content_type;
                const typeClass = r.content_type;
                const tableName = r.table_name || '';
                const question = r.question || '';
                const answer = r.content_text || '';

                let answerHtml = _formatMLAnswer(answer);

                // v3.28.7: kart başlığına schema/table data-attribute'ları — sample lazy-load için
                const metaRaw = r.metadata || {};
                const schemaName = metaRaw.schema_name || '';
                const fullTable = metaRaw.full_table || (schemaName ? `${schemaName}.${tableName}` : tableName);
                const escSchema = _escapeHtml(schemaName);
                const escTable = _escapeHtml(tableName);
                const escScript = _escapeHtml(answer);

                return `
                    <div class="ds-lr-card" data-idx="${idx}" data-source-id="${sourceId}" data-schema="${escSchema}" data-table="${escTable}">
                        <div class="ds-lr-card-header" onclick="window.DSLearningModule.toggleResultCard(this)">
                            <div class="ds-lr-card-meta">
                                <span class="ds-lr-type-badge ${typeClass}">${typeLabel}</span>
                                ${tableName ? `<span class="ds-lr-table-name"><i class="fa-solid fa-table"></i> ${_escapeHtml(tableName)}</span>` : ''}
                            </div>
                            <div class="ds-lr-card-question">
                                <i class="fa-solid fa-circle-question"></i>
                                <span>${_escapeHtml(question) || 'Soru bilgisi yok'}</span>
                            </div>
                            <i class="fa-solid fa-chevron-down ds-lr-chevron"></i>
                        </div>
                        <div class="ds-lr-card-body">
                            <div class="ds-lr-answer">
                                <div class="ds-lr-answer-label"><i class="fa-solid fa-robot"></i> ML Cevabı</div>
                                <div class="ds-lr-answer-text">${answerHtml}</div>
                            </div>
                            <details class="ds-lr-script">
                                <summary><i class="fa-solid fa-code"></i> Öğrenilen Script (ham metin)</summary>
                                <pre class="ds-lr-script-pre">${escScript}</pre>
                            </details>
                            <div class="ds-lr-sample-slot" data-loaded="0" aria-live="polite">
                                <div class="ds-lr-sample-placeholder">
                                    <i class="fa-solid fa-database"></i>
                                    <span>Örnek veri kart açılınca yüklenecek (${_escapeHtml(fullTable)})</span>
                                </div>
                            </div>
                        </div>
                    </div>
                `;
            }).join('');

            // Pagination render
            if (renderPaginationFn) {
                renderPaginationFn({ page: currentPage, total_pages: totalPages, total_filtered: totalFiltered });
            }

            // Sayfa değişiminde scroll to top
            if (!isPolling && stateRef && stateRef.page > 1) {
                body.scrollTop = 0;
            }

        } catch (err) {
            body.innerHTML = `<div class="ds-lr-error">Yükleme hatası: ${_escapeHtml(err.message)}</div>`;
        }
    }

    // ============================================
    // Helpers
    // ============================================

    function _escapeHtml(str) {
        if (!str) return '';
        return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
    }

    function _formatMLAnswer(str) {
        if (!str) return '';
        let esc = _escapeHtml(str);

        // 1. Ana Başlıklar (TABLO:, İş Adı: vs.)
        esc = esc.replace(/^(TABLO:|İş Adı:|Açıklama:|Sütunlar:)/gm, '<span class="ds-lr-txt-key">$1</span>');

        // 2. Sütun Adları ve Tipler: " - PartyId (integer) → İş Adı:"
        esc = esc.replace(/^(\s*-\s*)([a-zA-Z0-9_ığüşöçİĞÜŞÖÇ]+)(\s*\([^)]+\))/gm, 
            '$1<span class="ds-lr-txt-col">$2</span><span class="ds-lr-txt-type">$3</span>');

        // 3. Eşanlamlılar: "Eşanlamlılar: [kullanıcı numarası, personel ID]"
        esc = esc.replace(/(Eşanlamlılar:\s*)(\[[^\]]+\])/g, '<strong>$1</strong><span class="ds-lr-txt-synonym">$2</span>');

        // 4. Olası Değerler: "    Olası Değerler: 675477, ..."
        esc = esc.replace(/^(.*)(Olası Değerler:)(.*)$/gm, '$1<span class="ds-lr-txt-values"><strong>$2</strong>$3</span>');

        // 5. [ARANABİLİR] Badge çevrimi
        esc = esc.replace(/\[ARANABİLİR\]/g, '<span class="ds-lr-badge-searchable"><i class="fa-solid fa-search"></i> ARANABİLİR</span>');

        return esc;
    }

    function _formatNumber(num) {
        if (!num || num <= 0) return '0';
        return new Intl.NumberFormat('tr-TR').format(num);
    }

    function _formatDateTime(isoString) {
        if (!isoString) return '-';
        const date = new Date(isoString);
        if (isNaN(date.getTime())) return '-';
        const dd = String(date.getDate()).padStart(2, '0');
        const mm = String(date.getMonth() + 1).padStart(2, '0');
        const yyyy = date.getFullYear();
        const hh = String(date.getHours()).padStart(2, '0');
        const mi = String(date.getMinutes()).padStart(2, '0');
        return `${dd}/${mm}/${yyyy} ${hh}:${mi}`;
    }

    // ============================================
    // Init
    // ============================================

    // QA Üretimi kaldırıldı — Tam Pipeline (run-full-learning) tüm adımları içerir

    // ============================================
    // Tam Pipeline çalıştırma
    // ============================================

    async function runFullLearning(sourceId, sourceName) {
        _currentSourceId = sourceId;
        _currentSourceName = sourceName;

        // Çalışan iş kontrolü (frontend guard)
        try {
            const check = await apiCall(`/${sourceId}/check-running-job`);
            if (check.has_running && check.job) {
                const jobLabels = {
                    'technology': 'Teknoloji Keşfi', 'objects': 'Obje Tespiti',
                    'samples': 'Veri Toplama', 'learning': 'Şema Öğrenimi',
                    'qa_generation': 'Şema Öğrenimi', 'schema_learning': 'Şema Öğrenimi',
                    'full_learning': 'Tam Pipeline'
                };
                const label = jobLabels[check.job.job_type] || check.job.job_type;
                toast('warning', `⚠️ Bu kaynak için "${label}" işi hâlâ çalışıyor. Tamamlanmasını beklemelisiniz.`);
                return;
            }
        } catch (e) {
            console.warn('[DSLearning] Running job kontrolü yapılamadı:', e);
        }

        try {
            const result = await apiCall(`/${sourceId}/run-full-learning`, 'POST');
            if (result.success) {
                toast('success', result.message || 'Tam öğrenme pipeline başlatıldı');
            } else {
                // Backend guard mesajını göster
                toast('error', 'Pipeline başlatılamadı: ' + (result.message || ''));
            }
        } catch (err) {
            toast('error', 'Pipeline hatası: ' + err.message);
        }
    }

    // ============================================
    // v3.27.0 — DB Öğrenme Loop (G1+G3+G4)
    // ============================================

    let _dbLoopPollTimer = null;

    async function openDbLearningLoop(sourceId, sourceName) {
        _currentSourceId = sourceId;
        _currentSourceName = sourceName;

        const existing = document.getElementById('dsDbLoopModal');
        if (existing) existing.remove();

        const modal = document.createElement('div');
        modal.id = 'dsDbLoopModal';
        modal.className = 'ds-wizard-overlay';
        modal.innerHTML = `
            <div class="ds-wizard-modal" style="max-width: 880px;">
                <div class="ds-wizard-header">
                    <div class="ds-wizard-title">
                        <i class="fa-solid fa-robot"></i>
                        <span>DB Öğrenme Loop — ${_escapeHtml(sourceName)}</span>
                    </div>
                    <button class="ds-wizard-close" id="dsDbLoopClose" title="Kapat">
                        <i class="fa-solid fa-times"></i>
                    </button>
                </div>
                <div class="ds-wizard-body" style="padding: 1.25rem 1.5rem;">
                    <div class="ds-dbloop-intro">
                        <p><strong>FK ilişkilerinden otomatik örnek üret:</strong> Her FK için 2 sentetik SQL (LOOKUP_JOIN + AGGREGATE_COUNT) hedef DB'de çalıştırılır ve <em>learned_db_queries</em> önbelleğine yazılır. Tekrar üretim yapılmaz (idempotent).</p>
                    </div>
                    <div class="ds-dbloop-actions" style="display:flex; gap:0.5rem; margin: 0.75rem 0 1rem;">
                        <button class="ds-wizard-btn primary" id="dsDbLoopGenBtn">
                            <i class="fa-solid fa-bolt"></i> Sentetik SQL Üret (FK Loop)
                        </button>
                        <button class="ds-wizard-btn secondary" id="dsDbLoopRefreshBtn">
                            <i class="fa-solid fa-rotate"></i> Yenile
                        </button>
                    </div>
                    <div id="dsDbLoopStatus" class="ds-dbloop-status"></div>
                    <h4 style="margin: 1rem 0 0.5rem;">Öğrenilmiş Sorgular</h4>
                    <div id="dsDbLoopList" class="ds-dbloop-list">
                        <div class="ds-loading"><i class="fa-solid fa-spinner fa-spin"></i> Yükleniyor...</div>
                    </div>
                    <h4 style="margin: 1.25rem 0 0.5rem; color:#dc2626;">Başarısız Denemeler</h4>
                    <div id="dsDbLoopFailures" class="ds-dbloop-failures">
                        <div class="ds-loading"><i class="fa-solid fa-spinner fa-spin"></i> Yükleniyor...</div>
                    </div>
                </div>
            </div>
        `;
        document.body.appendChild(modal);
        requestAnimationFrame(() => modal.classList.add('active'));

        const closeLoop = () => {
            if (_dbLoopPollTimer) { clearInterval(_dbLoopPollTimer); _dbLoopPollTimer = null; }
            modal.classList.remove('active');
            setTimeout(() => modal.remove(), 300);
            document.removeEventListener('keydown', escH);
        };
        function escH(e) { if (e.key === 'Escape') closeLoop(); }
        document.addEventListener('keydown', escH);
        document.getElementById('dsDbLoopClose').addEventListener('click', closeLoop);

        document.getElementById('dsDbLoopGenBtn').addEventListener('click', () => triggerSyntheticGeneration(sourceId));
        document.getElementById('dsDbLoopRefreshBtn').addEventListener('click', () => {
            loadDbLoopStatus(sourceId);
            loadLearnedQueries(sourceId);
            loadSyntheticFailures(sourceId);
        });

        await loadDbLoopStatus(sourceId);
        await loadLearnedQueries(sourceId);
        await loadSyntheticFailures(sourceId);
    }

    async function triggerSyntheticGeneration(sourceId) {
        const btn = document.getElementById('dsDbLoopGenBtn');
        if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Başlatılıyor...'; }
        try {
            const res = await apiCall(`/${sourceId}/generate-synthetic-queries`, 'POST', { skip_existing: true });
            if (res.success) {
                toast('success', res.message || 'Sentetik üretim başlatıldı');
                _startStatusPolling(sourceId);
            } else {
                toast('warning', res.message || 'Başlatılamadı');
            }
        } catch (e) {
            toast('error', 'Hata: ' + (e.message || e));
        } finally {
            if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fa-solid fa-bolt"></i> Sentetik SQL Üret (FK Loop)'; }
        }
    }

    function _startStatusPolling(sourceId) {
        if (_dbLoopPollTimer) clearInterval(_dbLoopPollTimer);
        let ticks = 0;
        _dbLoopPollTimer = setInterval(async () => {
            ticks++;
            const done = await loadDbLoopStatus(sourceId);
            if (done || ticks > 120) { // 2 dakika cap
                clearInterval(_dbLoopPollTimer);
                _dbLoopPollTimer = null;
                if (done) {
                    loadLearnedQueries(sourceId);
                    loadSyntheticFailures(sourceId);
                }
            }
        }, 1500);
    }

    async function loadDbLoopStatus(sourceId) {
        const box = document.getElementById('dsDbLoopStatus');
        if (!box) return false;
        // a11y: durum mesajlarını ekran okuyucu canlı bildirim alanı olarak işaretle
        if (box.getAttribute('aria-live') !== 'polite') {
            box.setAttribute('aria-live', 'polite');
            box.setAttribute('aria-atomic', 'true');
        }
        try {
            const res = await apiCall(`/${sourceId}/synthetic-status`);
            const job = res.job || { status: 'idle' };
            const status = job.status || 'idle';
            let html = '';
            if (status === 'running') {
                html = _renderDbLoopProgress(job, /*done*/ false);
            } else if (status === 'done') {
                const s = job.summary || {};
                // G2.2 — FK ilişkisi yoksa empty state
                if ((s.total_fks ?? 0) === 0) {
                    html = `
                        <div class="ds-dbloop-empty-state" role="status">
                            <i class="fa-solid fa-link-slash" aria-hidden="true"></i>
                            <h3>FK ilişkisi bulunamadı</h3>
                            <p>Bu veri kaynağında henüz FK tanımlı değil. "Veri Kaynakları" sayfasından kaynağı yeniden keşfedin veya FK çıkarımı (auto-inference) çalıştırın.</p>
                        </div>
                    `;
                } else {
                    html = _renderDbLoopProgress(job, /*done*/ true);
                }
            } else if (status === 'error') {
                html = `<div class="ds-dbloop-pill ds-dbloop-error" role="alert"><i class="fa-solid fa-circle-exclamation" aria-hidden="true"></i> Hata: ${_escapeHtml(job.error || 'bilinmeyen')}</div>`;
            } else {
                html = `<div class="ds-dbloop-pill ds-dbloop-idle">Henüz çalıştırılmadı</div>`;
            }
            box.innerHTML = html;

            // "Detaylar" expander davranışı
            const detailsBtn = box.querySelector('#dsDbLoopDetailsBtn');
            const detailsPanel = box.querySelector('#dsDbLoopDetailsPanel');
            if (detailsBtn && detailsPanel) {
                detailsBtn.addEventListener('click', () => {
                    const open = detailsPanel.style.display !== 'none';
                    detailsPanel.style.display = open ? 'none' : 'flex';
                    detailsBtn.setAttribute('aria-expanded', String(!open));
                });
            }
            return status === 'done' || status === 'error';
        } catch (e) {
            box.innerHTML = `<div class="ds-dbloop-pill ds-dbloop-error" role="alert"><i class="fa-solid fa-circle-exclamation" aria-hidden="true"></i> Durum alınamadı</div>`;
            return true;
        }
    }

    // v3.32.0 G2.1 — Progress bar render (running + done ortak)
    function _renderDbLoopProgress(job, done) {
        const s = job.summary || {};
        const dialect = job.dialect || '?';
        const total = Number(s.total_attempts ?? 0);
        const success = Number(s.success ?? 0);
        const skippedExisting = Number(s.skipped_existing ?? 0);
        const skippedEmpty = Number(s.skipped_empty ?? 0);
        const skippedRecent = Number(s.skipped_recent_failure ?? 0);
        const skippedTotal = skippedExisting + skippedEmpty + skippedRecent;
        const failExecute = Number(s.failed_execute ?? 0);
        const failLearn = Number(s.failed_learn ?? 0);
        const failed = failExecute + failLearn;
        const junctionSuccess = Number(s.junction_success ?? 0);
        const totalFks = Number(s.total_fks ?? 0);
        const elapsedSec = s.elapsed_ms != null ? (Number(s.elapsed_ms) / 1000).toFixed(1) : null;

        // running iken summary boş gelmiş olabilir → indeterminate
        const hasSummary = Object.keys(s).length > 0 && total > 0;
        const completed = success + failed;
        const percent = hasSummary ? Math.max(0, Math.min(100, Math.round((completed / total) * 100))) : 0;
        const barIndeterminate = !done && !hasSummary;

        if (done) {
            return `
                <div class="ds-dbloop-progress done">
                    <i class="fa-solid fa-circle-check" aria-hidden="true" style="color: var(--green);"></i>
                    <span class="ds-dbloop-progress-summary">
                        Tamamlandı: <strong>${success}</strong> başarılı,
                        <strong>${skippedTotal}</strong> atlandı,
                        <strong>${failed}</strong> hata
                        ${elapsedSec != null ? `· ${elapsedSec}s` : ''}
                        ${dialect && dialect !== '?' ? `· ${_escapeHtml(dialect)}` : ''}
                    </span>
                    <button type="button" class="ds-link-btn" id="dsDbLoopDetailsBtn"
                            aria-label="Üretim detaylarını göster"
                            data-tooltip="Junction / skip dağılımı"
                            aria-expanded="false"
                            aria-controls="dsDbLoopDetailsPanel">
                        Detaylar
                    </button>
                    <div id="dsDbLoopDetailsPanel" class="ds-dbloop-progress-details" style="display:none;">
                        <span>FK: <strong>${totalFks}</strong></span>
                        <span>Denenen: <strong>${total}</strong></span>
                        <span>Junction (N:M): <strong>${junctionSuccess}</strong></span>
                        <span>Mevcut atlandı: <strong>${skippedExisting}</strong></span>
                        <span>Boş tablo atlandı: <strong>${skippedEmpty}</strong></span>
                        <span>Yakın hata atlandı: <strong>${skippedRecent}</strong></span>
                        <span>Execute hata: <strong>${failExecute}</strong></span>
                        <span>Öğrenme hata: <strong>${failLearn}</strong></span>
                    </div>
                </div>
            `;
        }

        // RUNNING
        const headLabel = hasSummary
            ? `Sentetik üretim çalışıyor... <strong>${completed}/${total}</strong> deneme`
            : `Başlatılıyor... (dialect: ${_escapeHtml(dialect)})`;
        const ariaNow = barIndeterminate ? '' : `aria-valuenow="${percent}"`;
        const barClass = barIndeterminate ? 'ds-dbloop-progress-bar indeterminate' : 'ds-dbloop-progress-bar';
        const fillStyle = barIndeterminate ? '' : `style="width: ${percent}%"`;

        return `
            <div class="ds-dbloop-progress">
                <div class="ds-dbloop-progress-header">
                    <i class="fa-solid fa-spinner fa-spin" aria-hidden="true"></i>
                    <span>${headLabel}</span>
                </div>
                <div class="${barClass}"
                     role="progressbar"
                     ${ariaNow}
                     aria-valuemin="0" aria-valuemax="100"
                     aria-label="FK Loop ilerleme${barIndeterminate ? ' (başlatılıyor)' : ''}">
                    <div class="ds-dbloop-progress-fill" ${fillStyle}></div>
                </div>
                <div class="ds-dbloop-progress-stats">
                    <span class="stat stat-success"><i class="fa-solid fa-circle-check" aria-hidden="true"></i> ${success} başarılı</span>
                    <span class="stat stat-skip"><i class="fa-solid fa-circle-minus" aria-hidden="true"></i> ${skippedTotal} atlandı</span>
                    <span class="stat stat-fail"><i class="fa-solid fa-circle-xmark" aria-hidden="true"></i> ${failed} hata</span>
                </div>
            </div>
        `;
    }

    async function loadLearnedQueries(sourceId) {
        const list = document.getElementById('dsDbLoopList');
        if (!list) return;
        list.innerHTML = '<div class="ds-loading"><i class="fa-solid fa-spinner fa-spin"></i> Yükleniyor...</div>';
        try {
            const res = await apiCall(`/${sourceId}/learned-queries?only_active=true&limit=50`);
            const items = (res && res.items) || [];
            if (!items.length) {
                list.innerHTML = '<div class="ds-dbloop-empty">Henüz öğrenilmiş sorgu yok. Yukarıdaki butonla başlat veya kullanıcı sorgusu çalıştır.</div>';
                return;
            }
            list.innerHTML = items.map(it => `
                <div class="ds-dbloop-row">
                    <div class="ds-dbloop-row-head">
                        <span class="ds-dbloop-badge ds-dbloop-src-${_escapeHtml(it.source || 'user')}">${_escapeHtml(it.source || 'user')}</span>
                        <span class="ds-dbloop-q">${_escapeHtml(it.question || '')}</span>
                        <span class="ds-dbloop-hit" title="hit_count">⚡ ${it.hit_count || 0}</span>
                        <button class="ds-dbloop-deact" data-id="${it.id}" title="Pasifleştir"><i class="fa-solid fa-ban"></i></button>
                    </div>
                    <pre class="ds-dbloop-sql">${_escapeHtml((it.sql_query || '').substring(0, 400))}</pre>
                </div>
            `).join('');
            list.querySelectorAll('.ds-dbloop-deact').forEach(b => {
                b.addEventListener('click', async () => {
                    const lid = parseInt(b.dataset.id, 10);
                    try {
                        await apiCall(`/${sourceId}/learned-queries/${lid}/deactivate`, 'POST');
                        toast('success', 'Pasifleştirildi');
                        loadLearnedQueries(sourceId);
                    } catch (e) {
                        toast('error', 'Hata: ' + (e.message || e));
                    }
                });
            });
        } catch (e) {
            list.innerHTML = `<div class="ds-dbloop-empty">Liste alınamadı: ${_escapeHtml(e.message || '')}</div>`;
        }
    }

    // v3.28.9 Paket C: başarısız sentetik denemeleri listele
    async function loadSyntheticFailures(sourceId) {
        const box = document.getElementById('dsDbLoopFailures');
        if (!box) return;
        box.innerHTML = '<div class="ds-loading"><i class="fa-solid fa-spinner fa-spin"></i> Yükleniyor...</div>';
        try {
            const res = await apiCall(`/${sourceId}/synthetic-failures?limit=50`);
            const items = (res && res.items) || [];
            if (!items.length) {
                box.innerHTML = '<div class="ds-dbloop-empty">Hatalı deneme yok.</div>';
                return;
            }
            // v3.32.0 G2.3 — accessible failure rows: ellipsis msg + tooltip + icon-only expand/copy buttons
            box.innerHTML = items.map((it, idx) => {
                const sqlId = `dsDbLoopFailSql_${idx}`;
                const rawMsg = it.error_message || 'bilinmeyen hata';
                const fromRel = `${it.from_table || ''}.${it.from_column || ''}`;
                const toRel = `${it.to_table || ''}.${it.to_column || ''}`;
                const renderedSql = it.rendered_sql || '';
                return `
                <div class="ds-dbloop-failrow-v2" data-idx="${idx}">
                    <div class="fail-head">
                        <span class="fail-kind">${_escapeHtml(it.template_kind || '?')}</span>
                        <span class="fail-rel">${_escapeHtml(fromRel)}</span>
                        <span class="fail-arrow" aria-hidden="true">→</span>
                        <span class="fail-rel">${_escapeHtml(toRel)}</span>
                        <span class="fail-time">${_escapeHtml(it.executed_at || '')}</span>
                    </div>
                    <div class="fail-msg">
                        <i class="fa-solid fa-circle-exclamation" aria-hidden="true"></i>
                        <span class="fail-msg-text" data-tooltip="${_escapeHtml(rawMsg)}" title="${_escapeHtml(rawMsg)}">${_escapeHtml(rawMsg)}</span>
                        <button type="button"
                                class="ds-dbloop-icon-btn ds-dbloop-fail-toggle"
                                data-target="${sqlId}"
                                aria-label="SQL'i göster/gizle"
                                data-tooltip="Tam SQL'i göster/gizle"
                                aria-expanded="false"
                                aria-controls="${sqlId}">
                            <i class="fa-solid fa-code" aria-hidden="true"></i>
                        </button>
                        <button type="button"
                                class="ds-dbloop-icon-btn ds-dbloop-fail-copy"
                                data-sql-target="${sqlId}"
                                aria-label="Tam SQL'i panoya kopyala"
                                data-tooltip="Tam SQL'i kopyala">
                            <i class="fa-solid fa-copy" aria-hidden="true"></i>
                        </button>
                    </div>
                    <div class="fail-sql-wrap">
                        <pre id="${sqlId}" class="fail-sql">${_escapeHtml(renderedSql)}</pre>
                    </div>
                </div>
            `;
            }).join('');

            // Expand/collapse handlers
            box.querySelectorAll('.ds-dbloop-fail-toggle').forEach(btn => {
                btn.addEventListener('click', () => {
                    const row = btn.closest('.ds-dbloop-failrow-v2');
                    if (!row) return;
                    const isOpen = row.classList.toggle('expanded');
                    btn.setAttribute('aria-expanded', String(isOpen));
                });
            });
            // Copy handlers
            box.querySelectorAll('.ds-dbloop-fail-copy').forEach(btn => {
                btn.addEventListener('click', async () => {
                    const id = btn.getAttribute('data-sql-target');
                    const pre = id ? document.getElementById(id) : null;
                    const text = pre ? pre.textContent : '';
                    if (!text) {
                        toast('warning', 'Kopyalanacak SQL bulunamadı');
                        return;
                    }
                    try {
                        if (navigator.clipboard && navigator.clipboard.writeText) {
                            await navigator.clipboard.writeText(text);
                        } else {
                            const ta = document.createElement('textarea');
                            ta.value = text;
                            ta.setAttribute('readonly', '');
                            ta.style.position = 'fixed';
                            ta.style.opacity = '0';
                            document.body.appendChild(ta);
                            ta.select();
                            document.execCommand('copy');
                            document.body.removeChild(ta);
                        }
                        toast('success', 'SQL kopyalandı');
                    } catch (err) {
                        toast('error', 'Kopyalama başarısız: ' + (err.message || err));
                    }
                });
            });
        } catch (e) {
            box.innerHTML = `<div class="ds-dbloop-empty">Hatalar alınamadı: ${_escapeHtml(e.message || '')}</div>`;
        }
    }

